import math
from openai import OpenAI

client = OpenAI()

# -----------------------------------------------------------------------
# Advanced: segment logprobs to score only the tool-call span
# -----------------------------------------------------------------------

TOOL_START_TOKEN = '"name"'  # sentinel in tool-call JSON

def score_tool_call_span(messages: list[dict]) -> dict:
    """
    Request a function-call completion with logprobs, then extract the
    logprob segment that covers the tool name and parameters only —
    ignoring surrounding JSON boilerplate that inflates the average.
    """
    tools = [
        {
            "type": "function",
            "function": {
                "name": "search_database",
                "description": "Search a product database.",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "query": {"type": "string"},
                        "max_results": {"type": "integer"},
                    },
                    "required": ["query"],
                },
            },
        }
    ]
    resp = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=messages,
        tools=tools,
        tool_choice="auto",
        logprobs=True,
        top_logprobs=3,
    )
    choice = resp.choices[0]
    all_lps = [(lp.token, lp.logprob) for lp in (choice.logprobs.content or [])]

    # Find where the meaningful content starts (after opening boilerplate)
    # For a simple heuristic: skip structural tokens, keep value tokens
    value_tokens = [
        (tok, lp) for tok, lp in all_lps
        if not tok.strip() in {"{", "}", "[", "]", ":", ",", "null", "true", "false"}
    ]
    if not value_tokens:
        return {"mean_lp": None, "low_confidence": True}

    mean_lp = sum(lp for _, lp in value_tokens) / len(value_tokens)
    min_lp  = min(lp for _, lp in value_tokens)
    low_conf_tokens = [(tok, lp) for tok, lp in value_tokens if lp < -2.0]

    return {
        "tool_name": choice.message.tool_calls[0].function.name if choice.message.tool_calls else None,
        "mean_lp": round(mean_lp, 3),
        "min_lp":  round(min_lp, 3),
        "low_confidence": mean_lp < -1.5,
        "suspect_tokens": low_conf_tokens[:5],
    }

result = score_tool_call_span([
    {"role": "user", "content": "Find products matching wireless headphones under 100 dollars."}
])
print(result)
